import React, { useState } from 'react';
import { useSupabase } from '../context/SupabaseContext';

export default function LoginPage() {
  const { client } = useSupabase();
  const [email, setEmail]       = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading]   = useState(false);
  const [error, setError]       = useState('');

  const handle = async e => {
    e.preventDefault(); setLoading(true); setError('');
    const { error: err } = await client.auth.signInWithPassword({ email, password });
    if (err) setError(err.message);
    setLoading(false);
  };

  return (
    <div style={{ minHeight:'100vh', background:'#0F172A', display:'flex', alignItems:'center', justifyContent:'center', fontFamily:'Inter, sans-serif' }}>
      <div style={{ width:'100%', maxWidth:420, padding:16 }}>
        {/* Card */}
        <div style={{ background:'#1E293B', border:'1px solid rgba(255,255,255,0.08)', borderRadius:16, padding:'48px 44px', boxShadow:'0 24px 48px rgba(0,0,0,0.4)' }}>
          <div style={{ textAlign:'center', marginBottom:32 }}>
            <div style={{ width:56, height:56, borderRadius:14, background:'#1D4ED8', display:'flex', alignItems:'center', justifyContent:'center', fontSize:28, margin:'0 auto 14px' }}>🚛</div>
            <h1 style={{ margin:'0 0 6px', fontSize:22, fontWeight:800, color:'#fff' }}>FleetMS</h1>
            <p style={{ margin:0, fontSize:13, color:'rgba(255,255,255,0.4)' }}>Fleet Management System</p>
          </div>

          <form onSubmit={handle} style={{ display:'flex', flexDirection:'column', gap:14 }}>
            {['Email','Password'].map(f => (
              <div key={f}>
                <label style={{ fontSize:12, fontWeight:600, color:'rgba(255,255,255,0.5)', textTransform:'uppercase', letterSpacing:'0.4px', display:'block', marginBottom:5 }}>{f}</label>
                <input type={f==='Password'?'password':'email'} required
                  value={f==='Password'?password:email}
                  onChange={e => f==='Password'?setPassword(e.target.value):setEmail(e.target.value)}
                  style={{ width:'100%', padding:'10px 14px', background:'rgba(255,255,255,0.06)', border:'1px solid rgba(255,255,255,0.12)', borderRadius:8, fontSize:14, outline:'none', fontFamily:'inherit', boxSizing:'border-box', color:'#fff' }}
                  placeholder={f==='Password'?'••••••••':'you@company.com'} />
              </div>
            ))}
            {error && <p style={{ margin:0, fontSize:13, color:'#FCA5A5', background:'rgba(220,38,38,0.1)', padding:'8px 12px', borderRadius:7, border:'1px solid rgba(220,38,38,0.3)' }}>{error}</p>}
            <button type="submit" disabled={loading}
              style={{ padding:11, background:'#1D4ED8', color:'#fff', border:'none', borderRadius:8, fontSize:14, fontWeight:700, cursor:loading?'not-allowed':'pointer', fontFamily:'inherit', opacity:loading?0.7:1, marginTop:4 }}>
              {loading?'Signing in…':'Sign In'}
            </button>
          </form>
        </div>

        {/* Footer */}
        <div style={{ textAlign:'center', marginTop:20 }}>
          <a href="https://messaging-service.co.tz/" target="_blank" rel="noopener noreferrer"
            style={{ fontSize:12, color:'#60A5FA', fontWeight:700, textDecoration:'none' }}>Staff-SMS</a>
          <span style={{ fontSize:12, color:'rgba(255,255,255,0.3)' }}> · FleetMS © {new Date().getFullYear()}</span>
        </div>
      </div>
    </div>
  );
}
